/* UserLoginRepository.updateLoginInfo */
UPDATE MH_EXT_MEMBER
SET MEMBER_RECENT_LOGIN = NOW()

        , LAST_LOGIN_IP = #{lastLoginIp}

WHERE MEMBER_ID = #{memberId}
  AND ACCOUNT_STATUS = 'A'

/* UserLoginRepository.updateFirstLogin */
UPDATE MH_EXT_MEMBER
SET MEMBER_FIRST_LOGIN = NOW()
WHERE MEMBER_ID = #{memberId}
  AND ACCOUNT_STATUS = 'A'
  AND MEMBER_FIRST_LOGIN IS NULL
